mapper.select:
select f.facility_id, f.ent_code, e.ent_name, f.out_put_type, f.facility_code, f.facility_name, f.pollutant, f.govern_process, f.efficiency, f.design_capacity, f.actual_operating_rate, f.install_date, f.remark, f.create_time, f.update_time from t_ent_poll_control_facility f left join t_bas_enterprise e on e.ent_code = f.ent_code
and f.ent_code = #{entCode}
and f.ent_code in
#{entCode}
and f.out_put_type = #{outPutType}
and e.ent_name like concat('%', #{entName}, '%')
and f.facility_name like concat('%', #{facilityName}, '%')
order by f.facility_id desc
